module counter_module (
        input clk_inv,
        input reset,
        input up_down,
        output reg [3:0] count);always @(posedge clk_inv) begin
    if (reset)
        count <= 4'b0000;
    else if (up_down)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
